class ReservationStep1View(View):
    def get(self, request):
        form = ReservationStep1Form()
        return render(request, 'reservations/step1.html', {'form': form})

    def post(self, request):
        form = ReservationStep1Form(request.POST)
        if form.is_valid():
            request.session['reservation_fecha_inicio'] = str(form.cleaned_data['fecha_inicio'])
            request.session['reservation_fecha_fin'] = str(form.cleaned_data['fecha_fin'])
