        context = super().get_context_data(**kwargs)
        return context

class CancelReservationView(View):
    def post(self, request, codigo):
        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
        except Reserva.DoesNotExist:
            messages.error(request, 'No se encontró la reserva.')
            return redirect('tracking:search')

        if reserva.estado in ['EN_USO', 'DEVUELTO']:
            messages.error(request, 'No se puede cancelar una reserva en uso o devuelta.')
            return redirect('tracking:detail', codigo=codigo)

        reserva.estado = 'CANCELADA'
        reserva.save()

        HistorialReserva.objects.create(
            reserva=reserva,
            estado_anterior=reserva.estado,
            estado_nuevo='CANCELADA',
            cambio_realizado_por=request.user if request.user.is_authenticated else None,
            notas='Reserva cancelada por el cliente'
        )

        messages.success(request, 'Reserva cancelada correctamente.')
        return redirect('tracking:detail', codigo=codigo)

from django.shortcuts import render, get_object_or_404
from django.views import View
from django.views.generic import TemplateView, ListView
from django.contrib.auth.mixins import LoginRequiredMixin
from reservations.models import Reserva, LineaReserva

class TrackingSearchView(View):
    def get(self, request):
        return render(request, 'tracking/search.html')

    def post(self, request):
        codigo = request.POST.get('codigo', '').strip().upper()
        if codigo:
            try:
                reserva = Reserva.objects.get(codigo_seguimiento=codigo)
                return render(request, 'tracking/detail.html', {'reserva': reserva})
            except Reserva.DoesNotExist:
                return render(request, 'tracking/search.html', {'error': 'No se encontró la reserva con ese código.'})

        return render(request, 'tracking/search.html', {'error': 'Por favor, ingresa un código de seguimiento.'})

class TrackingDetailView(TemplateView):
    template_name = 'tracking/detail.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        codigo = kwargs.get('codigo')
        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
            lineas = LineaReserva.objects.filter(reserva=reserva)
            context['reserva'] = reserva
            context['lineas'] = lineas
        except Reserva.DoesNotExist:
            context['error'] = 'No se encontró la reserva.'
        return context

class MyReservationsView(LoginRequiredMixin, ListView):
    model = Reserva
    template_name = 'tracking/my_reservations.html'
    context_object_name = 'reservas'
    login_url = 'accounts:login'
    paginate_by = 10

    def get_queryset(self):
        return Reserva.objects.filter(cliente=self.request.user).order_by('-created_at')

