                        <td style="padding: 10px; text-align: right;">{{ reserva.importe_total }}€</td>
                        <td style="padding: 10px; text-align: center;">
                            <a href="{% url 'tracking:detail' reserva.codigo_seguimiento %}" style="color: #003d82; text-decoration: none;">Ver detalles</a>
                        </td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>

        {% if is_paginated %}
            <div style="margin-top: 30px; text-align: center;">
                {% if page_obj.has_previous %}
                    <a href="?page=1">Primera</a>
                    <a href="?page={{ page_obj.previous_page_number }}">Anterior</a>
                {% endif %}

                <span>Página {{ page_obj.number }} de {{ page_obj.paginator.num_pages }}</span>

                {% if page_obj.has_next %}
                    <a href="?page={{ page_obj.next_page_number }}">Siguiente</a>
                    <a href="?page={{ page_obj.paginator.num_pages }}">Última</a>
                {% endif %}
            </div>
        {% endif %}
    {% else %}
        <p>No tienes reservas aún.</p>
        <a href="{% url 'catalog:barco_list' %}" style="color: #003d82; text-decoration: none;">Ir al catálogo</a>
    {% endif %}
</div>
{% endblock %}

from decimal import Decimal

class CartService:
    CART_SESSION_KEY = 'cart'

    @staticmethod
    def get_cart(request):
        if CartService.CART_SESSION_KEY not in request.session:
            request.session[CartService.CART_SESSION_KEY] = {}
        return request.session[CartService.CART_SESSION_KEY]

    @staticmethod
    def add_to_cart(request, barco_id, cantidad):
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            cart[barco_id_str]['cantidad'] += cantidad
        else:
            from catalog.models import Barco
            barco = Barco.objects.get(id=barco_id)
            cart[barco_id_str] = {
                'nombre': barco.nombre,
                'precio_dia': str(barco.precio_dia),
                'cantidad': cantidad,
                'barco_id': barco_id
            }

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def update_cart(request, barco_id, cantidad):
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            if cantidad <= 0:
                del cart[barco_id_str]
            else:
                cart[barco_id_str]['cantidad'] = cantidad

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def clear_cart(request):
        request.session[CartService.CART_SESSION_KEY] = {}
        request.session.modified = True

    @staticmethod
    def get_cart_total(request):
        cart = CartService.get_cart(request)
        total = Decimal('0')
        for item in cart.values():
            total += Decimal(item['precio_dia']) * item['cantidad']
        return total

    @staticmethod
    def get_cart_count(request):
        cart = CartService.get_cart(request)
        count = 0
        for item in cart.values():
            count += item['cantidad']
        return count

from django.shortcuts import render, redirect
from django.views import View
from django.contrib.auth import authenticate, login, logout
from django.contrib.auth.models import User
from django.contrib.auth.mixins import LoginRequiredMixin
from django.contrib import messages
from django.views.generic import TemplateView
from .forms import RegistroForm, LoginForm
from .models import ClienteProfile

class RegisterView(View):
    def get(self, request):
        form = RegistroForm()
        return render(request, 'accounts/register.html', {'form': form})

    def post(self, request):
        form = RegistroForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']

            user = User.objects.create_user(username=email, email=email, password=password)
            ClienteProfile.objects.create(usuario=user)

            user = authenticate(username=email, password=password)
            login(request, user)
            messages.success(request, 'Registro exitoso. Bienvenido a Hundidos.')

            next_url = request.GET.get('next', '/')
            return redirect(next_url)

        return render(request, 'accounts/register.html', {'form': form})

class LoginView(View):
    def get(self, request):
        form = LoginForm()
        return render(request, 'accounts/login.html', {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']

            user = authenticate(username=email, password=password)
            if user is not None:
                login(request, user)
                messages.success(request, f'Bienvenido, {email}.')

                next_url = request.GET.get('next', '/')
                return redirect(next_url)
            else:
                messages.error(request, 'Correo o contraseña incorrectos.')

        return render(request, 'accounts/login.html', {'form': form})

class LogoutView(LoginRequiredMixin, View):
    def post(self, request):
        logout(request)
        messages.success(request, 'Has cerrado sesión correctamente.')
        return redirect('/')

class ProfileView(LoginRequiredMixin, TemplateView):
    template_name = 'accounts/profile.html'
    login_url = 'accounts:login'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['user'] = self.request.user
        try:
            context['profile'] = self.request.user.cliente_profile
        except:
            context['profile'] = None
        return context
